targets.expr:
topk(
  100,
  sum by (instance_uuid, project_uuid, project_name, user_uuid) (
    label_replace(
      oie_instance_threat_tor_exit_contacts_total{
        job="openstack-instance-exporter",
        instance=~"$gvar_oie_hypervisor",
        project_uuid=~"$gvar_oie_project_uuid",
        project_name=~"$gvar_oie_project_name",
        instance_uuid=~"$gvar_oie_instance_uuid"
      },
      "threat_source","tor_exit","",""
    )
  or label_replace(
      oie_instance_threat_tor_relay_contacts_total{
        job="openstack-instance-exporter",
        instance=~"$gvar_oie_hypervisor",
        project_uuid=~"$gvar_oie_project_uuid",
        project_name=~"$gvar_oie_project_name",
        instance_uuid=~"$gvar_oie_instance_uuid"
      },
      "threat_source","tor_relay","",""
    )
  or label_replace(
      oie_instance_threat_spamhaus_contacts_total{
        job="openstack-instance-exporter",
        instance=~"$gvar_oie_hypervisor",
        project_uuid=~"$gvar_oie_project_uuid",
        project_name=~"$gvar_oie_project_name",
        instance_uuid=~"$gvar_oie_instance_uuid"
      },
      "threat_source","spamhaus","",""
    )
  or label_replace(
      oie_instance_threat_emergingthreats_contacts_total{
        job="openstack-instance-exporter",
        instance=~"$gvar_oie_hypervisor",
        project_uuid=~"$gvar_oie_project_uuid",
        project_name=~"$gvar_oie_project_name",
        instance_uuid=~"$gvar_oie_instance_uuid"
      },
      "threat_source","emergingthreats","",""
    )
  or label_replace(
      oie_instance_threat_customlist_contacts_total{
        job="openstack-instance-exporter",
        instance=~"$gvar_oie_hypervisor",
        project_uuid=~"$gvar_oie_project_uuid",
        project_name=~"$gvar_oie_project_name",
        instance_uuid=~"$gvar_oie_instance_uuid"
      },
      "threat_source","customlist","",""
    )
  )
)
